3: import "context"
4: 
5: // V38 migrates table panel configuration from displayMode to the structured cellOptions format.
6: //
7: // This migration addresses limitations in the original table panel cell display configuration where
8: // the flat displayMode string property could not accommodate the growing complexity of cell rendering
9: // options. The original design forced all display settings into a single string value, making it
10: // difficult to add new customization parameters or provide mode-specific configuration options.
11: //
12: // The migration works by:
13: // 1. Locating table panels in the dashboard (including nested panels within rows)
14: // 2. Examining field configuration defaults and any field overrides for displayMode properties
15: // 3. Converting string displayMode values to structured cellOptions objects with type and mode
16: // 4. Updating both field defaults and field override references to use the new property path
17: // 5. Preserving all existing visual behavior while enabling future cell customization features
18: //
19: // This restructuring provides several key benefits:
20: // - Enables mode-specific configuration options (e.g., gauge thresholds, color schemes)
21: // - Supports future cell rendering types without breaking existing configurations
22: // - Provides clearer separation between cell type and rendering mode
23: // - Maintains backward compatibility while preparing for enhanced table functionality
24: //
25: // The migration handles special cases for legacy gauge modes and color background variants,
26: // ensuring all existing display behaviors are preserved exactly.
27: //
28: // Example transformations:
29: //
30: // Before migration (field defaults):
31: //
32: //	fieldConfig: {
33: //	  defaults: {
34: //	    custom: {
35: //	      displayMode: "gradient-gauge"
36: //	    }
37: //	  }
38: //	}
39: //
40: // After migration (field defaults):
41: //
42: //	fieldConfig: {
43: //	  defaults: {
44: //	    custom: {
45: //	      cellOptions: {
46: //	        type: "gauge",
47: //	        mode: "gradient"
48: //	      }
49: //	    }
50: //	  }
51: //	}
52: //
53: // Before migration (field override):
54: //
55: //	overrides: [{
56: //	  matcher: { id: "byName", options: "CPU" },
57: //	  properties: [{
58: //	    id: "custom.displayMode",
59: //	    value: "color-background-solid"
60: //	  }]
61: //	}]
62: //
63: // After migration (field override):
64: //
65: //	overrides: [{
66: //	  matcher: { id: "byName", options: "CPU" },
67: //	  properties: [{
68: //	    id: "custom.cellOptions",
69: //	    value: {
70: //	      type: "color-background",
71: //	      mode: "basic"
72: //	    }
73: //	  }]
74: //	}]
75: func V38(_ context.Context, dashboard map[string]interface{}) error {
76: 	dashboard["schemaVersion"] = int(38)
77: 
78: 	panels, ok := dashboard["panels"].([]interface{})
79: 	if !ok {
80: 		return nil
81: 	}
82: 
83: 	// Process all panels, including nested ones
84: 	processPanelsV38(panels)
85: 
86: 	return nil
87: }
88: 
89: // processPanelsV38 recursively processes panels, including nested panels within rows
90: func processPanelsV38(panels []interface{}) {
91: 	for _, panel := range panels {
92: 		p, ok := panel.(map[string]interface{})
93: 		if !ok {
94: 			continue
95: 		}
96: 
97: 		// Process nested panels if this is a row panel
98: 		if p["type"] == "row" {
99: 			if nestedPanels, ok := p["panels"].([]interface{}); ok {
100: 				processPanelsV38(nestedPanels)
101: 			}
102: 			continue
103: 		}
104: 
105: 		// Only process table panels
106: 		if p["type"] != "table" {
107: 			continue
108: 		}
109: 
110: 		fieldConfig, ok := p["fieldConfig"].(map[string]interface{})
111: 		if !ok {
112: 			continue
113: 		}
114: 
115: 		// Process defaults.custom if it exists
116: 		if defaults, ok := fieldConfig["defaults"].(map[string]interface{}); ok {
117: 			if custom, ok := defaults["custom"].(map[string]interface{}); ok {
118: 				// Migrate displayMode to cellOptions in defaults
119: 				if displayMode, exists := custom["displayMode"]; exists {
120: 					if displayModeStr, ok := displayMode.(string); ok {
121: 						custom["cellOptions"] = migrateTableDisplayModeToCellOptions(displayModeStr)
122: 					}
123: 					// Delete the legacy field
124: 					delete(custom, "displayMode")
125: 				}
126: 			}
127: 		}
128: 
129: 		// Update any overrides referencing the cell display mode
130: 		// This must be called regardless of whether defaults.custom exists
131: 		migrateOverrides(fieldConfig)
132: 	}
133: }
134: 
135: // migrateOverrides updates the overrides configuration to use the new cellOptions format
136: func migrateOverrides(fieldConfig map[string]interface{}) {
137: 	overrides, ok := fieldConfig["overrides"].([]interface{})
138: 	if !ok {
139: 		return
140: 	}
141: 
142: 	for _, override := range overrides {
143: 		o, ok := override.(map[string]interface{})
144: 		if !ok {
145: 			continue
146: 		}
147: 
148: 		properties, ok := o["properties"].([]interface{})
149: 		if !ok {
150: 			continue
151: 		}
152: 
153: 		for _, property := range properties {
154: 			prop, ok := property.(map[string]interface{})
155: 			if !ok {
156: 				continue
157: 			}
158: 
159: 			// Update the id to cellOptions
160: 			if prop["id"] == "custom.displayMode" {
161: 				prop["id"] = "custom.cellOptions"
162: 				if value, ok := prop["value"]; ok {
163: 					if valueStr, ok := value.(string); ok {
164: 						prop["value"] = migrateTableDisplayModeToCellOptions(valueStr)
165: 					}
166: 				} else {
167: 					// If no value exists, add empty cellOptions object to match frontend behavior
168: 					// Frontend always assigns a value even when original displayMode had no value
169: 					// See: public/app/features/dashboard/state/DashboardMigrator.ts:880
170: 					// override.properties[j].value = migrateTableDisplayModeToCellOptions(overrideDisplayMode);
171: 					prop["value"] = map[string]interface{}{}
172: 				}
173: 			}
174: 		}
175: 	}
176: }
177: 
178: // migrateTableDisplayModeToCellOptions converts the old displayMode string to the new cellOptions format
179: func migrateTableDisplayModeToCellOptions(displayMode string) map[string]interface{} {
180: 	switch displayMode {
181: 	case "basic", "gradient-gauge", "lcd-gauge":
182: 		gaugeMode := "basic"
183: 		switch displayMode {
184: 		case "gradient-gauge":
185: 			gaugeMode = "gradient"
186: 		case "lcd-gauge":
187: 			gaugeMode = "lcd"
188: 		}
189: 		return map[string]interface{}{
190: 			"type": "gauge",
191: 			"mode": gaugeMode,
192: 		}
193: 
194: 	case "color-background", "color-background-solid":
195: 		mode := "basic"
196: 		if displayMode == "color-background" {
197: 			mode = "gradient"
198: 		}
199: 		return map[string]interface{}{
200: 			"type": "color-background",
201: 			"mode": mode,
202: 		}
203: 
204: 	default:
205: 		return map[string]interface{}{
206: 			"type": displayMode,
207: 		}
208: 	}
209: }
